import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { 
  listenAuction, startAuction, closeAuction, 
  listenPlayers, addPlayer, deletePlayer, 
  resetAllWins, clearAllRecords 
} from '../firebase/services';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [settings, setSettings] = useState({ monthlyAmount: 5000, totalPlayers: 10 });
  const [newPlayer, setNewPlayer] = useState({ name: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const unsubs = [
      listenAuction(setAuction),
      listenPlayers((data) => {
        // FILTER: Remove Admin from the list entirely
        const onlyPlayers = data.filter(p => !p.isAdmin);
        setPlayers(onlyPlayers);
      })
    ];
    return () => unsubs.forEach(u => u());
  }, []);

  const handleMaintenanceReset = async () => {
    if (!window.confirm("⚠️ DANGER: This will wipe ALL records and reset ALL winners for a new 10-month cycle. Continue?")) return;
    try {
      await clearAllRecords();
      await resetAllWins();
      toast.success("System completely reset for a fresh cycle!");
    } catch (err) { toast.error("Reset failed"); }
  };

  const handleAddPlayer = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await addPlayer(newPlayer.email, newPlayer.password, newPlayer.name);
      toast.success("Player added!");
      setNewPlayer({ name: '', email: '', password: '' });
    } catch (err) { toast.error(err.message); }
    finally { setLoading(false); }
  };

  return (
    <div className="page-wide">
      <div className="navbar">
        <div className="navbar-brand">👑 Admin Controller</div>
        <button className="btn btn-danger btn-sm" onClick={logout}>Logout</button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.5fr', gap: '20px' }}>
        <div className="sidebar">
          {/* ADD PLAYER */}
          <div className="card">
            <h3 className="card-title">Add Family Member</h3>
            <form onSubmit={handleAddPlayer} style={{ marginTop: '10px' }}>
              <input type="text" className="form-input" placeholder="Name" required value={newPlayer.name} onChange={e => setNewPlayer({...newPlayer, name: e.target.value})} />
              <input type="email" className="form-input" placeholder="Email" required value={newPlayer.email} onChange={e => setNewPlayer({...newPlayer, email: e.target.value})} />
              <input type="password" className="form-input" placeholder="Password" required value={newPlayer.password} onChange={e => setNewPlayer({...newPlayer, password: e.target.value})} />
              <button className="btn btn-primary btn-full" disabled={loading}>Add Member</button>
            </form>
          </div>

          {/* MAINTENANCE */}
          <div className="card" style={{ border: '1px solid rgba(255,0,0,0.2)' }}>
            <h3 className="card-title" style={{ color: '#ff4d4d' }}>System Maintenance</h3>
            <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginBottom: '10px' }}>Use this only to start a brand new yearly cycle.</p>
            <button className="btn btn-danger btn-sm btn-full" onClick={handleMaintenanceReset}>Wipe All Records & Reset</button>
          </div>
        </div>

        <div className="main">
          {/* AUCTION CONTROL */}
          <div className="card" style={{ textAlign: 'center' }}>
            <h3 className="card-title">Live Auction Status</h3>
            {auction?.active ? (
              <>
                <h1 style={{ color: 'var(--gold)', fontSize: '3rem' }}>₹{auction.currentBid}</h1>
                <p>Bidder: {auction.currentBidderName || "None"}</p>
                <button className="btn btn-danger btn-full" onClick={() => closeAuction(auction)}>End Auction</button>
              </>
            ) : (
              <button className="btn btn-primary btn-full" onClick={() => startAuction(settings)}>Start Monthly Auction</button>
            )}
          </div>

          {/* PLAYER LIST (No Admin Shown) */}
          <div className="card">
            <h3 className="card-title">Family Members ({players.length})</h3>
            <table className="records-table">
              <thead><tr><th>Name</th><th>Status</th><th>Action</th></tr></thead>
              <tbody>
                {players.map(p => (
                  <tr key={p.id}>
                    <td>{p.name}</td>
                    <td>{p.hasWon ? <span className="badge badge-green">Won</span> : "Eligible"}</td>
                    <td><button className="btn btn-danger btn-sm" onClick={() => deletePlayer(p.id)}>🗑️</button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}
